SELECT id, file_name, file_size, format, duration_seconds, file_path, status, created_at, updated_at
FROM video
WHERE id = #{id}

SELECT id, file_name, file_size, format, duration_seconds, file_path, status, created_at, updated_at
FROM video


        AND status = #{status}


        AND file_name LIKE CONCAT('%', #{keyword}, '%')


        AND DATE(created_at) >= #{startDate}


        AND DATE(created_at) <= #{endDate}


ORDER BY created_at DESC
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*)
FROM video


        AND status = #{status}


        AND file_name LIKE CONCAT('%', #{keyword}, '%')


        AND DATE(created_at) >= #{startDate}


        AND DATE(created_at) <= #{endDate}
